    17→package org.apache.kafka.tools;
    18→
    19→import org.apache.kafka.clients.consumer.ConsumerConfig;
    20→import org.apache.kafka.clients.consumer.ConsumerRebalanceListener;
    21→import org.apache.kafka.clients.consumer.ConsumerRecord;
    22→import org.apache.kafka.clients.consumer.ConsumerRecords;
    23→import org.apache.kafka.clients.consumer.KafkaConsumer;
    24→import org.apache.kafka.common.Metric;
    25→import org.apache.kafka.common.MetricName;
    26→import org.apache.kafka.common.TopicPartition;
    27→import org.apache.kafka.common.serialization.ByteArrayDeserializer;
    28→import org.apache.kafka.common.utils.Exit;
    29→import org.apache.kafka.common.utils.Utils;
    30→import org.apache.kafka.server.util.CommandDefaultOptions;
    31→import org.apache.kafka.server.util.CommandLineUtils;
    32→
    33→import org.slf4j.Logger;
    34→import org.slf4j.LoggerFactory;
    35→
    36→import java.io.IOException;
    37→import java.text.SimpleDateFormat;
    38→import java.time.Duration;
    39→import java.util.Collection;
    40→import java.util.Collections;
    41→import java.util.Map;
    42→import java.util.Properties;
    43→import java.util.Random;
    44→import java.util.Set;
    45→import java.util.concurrent.atomic.AtomicLong;
    46→
    47→import joptsimple.OptionException;
    48→import joptsimple.OptionSpec;
    49→
    50→import static joptsimple.util.RegexMatcher.regex;
    51→
    52→public class ConsumerPerformance {
    53→    private static final Logger LOG = LoggerFactory.getLogger(ConsumerPerformance.class);
    54→    private static final Random RND = new Random();
    55→
    56→    public static void main(String[] args) {
    57→        try {
    58→            LOG.info("Starting consumer...");
    59→            ConsumerPerfOptions options = new ConsumerPerfOptions(args);
    60→            AtomicLong totalMessagesRead = new AtomicLong(0);
    61→            AtomicLong totalBytesRead = new AtomicLong(0);
    62→            AtomicLong joinTimeMs = new AtomicLong(0);
    63→            AtomicLong joinTimeMsInSingleRound = new AtomicLong(0);
    64→
    65→            if (!options.hideHeader())
    66→                printHeader(options.showDetailedStats());
    67→
    68→            KafkaConsumer<byte[], byte[]> consumer = new KafkaConsumer<>(options.props());
    69→            long bytesRead = 0L;
    70→            long messagesRead = 0L;
    71→            long lastBytesRead = 0L;
    72→            long lastMessagesRead = 0L;
    73→            long currentTimeMs = System.currentTimeMillis();
    74→            long joinStartMs = currentTimeMs;
    75→            long startMs = currentTimeMs;
    76→            consume(consumer, options, totalMessagesRead, totalBytesRead, joinTimeMs,
    77→                bytesRead, messagesRead, lastBytesRead, lastMessagesRead,
    78→                joinStartMs, joinTimeMsInSingleRound);
    79→            long endMs = System.currentTimeMillis();
    80→
    81→            Map<MetricName, ? extends Metric> metrics = null;
    82→            if (options.printMetrics())
    83→                metrics = consumer.metrics();
    84→            consumer.close();
    85→
    86→            // print final stats
    87→            double elapsedSec = (endMs - startMs) / 1_000.0;
    88→            long fetchTimeInMs = (endMs - startMs) - joinTimeMs.get();
    89→            if (!options.showDetailedStats()) {
    90→                double totalMbRead = (totalBytesRead.get() * 1.0) / (1024 * 1024);
    91→                System.out.printf("%s, %s, %.4f, %.4f, %d, %.4f, %d, %d, %.4f, %.4f%n",
    92→                    options.dateFormat().format(startMs),
    93→                    options.dateFormat().format(endMs),
    94→                    totalMbRead,
    95→                    totalMbRead / elapsedSec,
    96→                    totalMessagesRead.get(),
    97→                    totalMessagesRead.get() / elapsedSec,
    98→                    joinTimeMs.get(),
    99→                    fetchTimeInMs,
   100→                    totalMbRead / (fetchTimeInMs / 1000.0),
   101→                    totalMessagesRead.get() / (fetchTimeInMs / 1000.0)
   102→                );
   103→            }
   104→
   105→            if (metrics != null)
   106→                ToolsUtils.printMetrics(metrics);
   107→        } catch (Throwable e) {
   108→            System.err.println(e.getMessage());
   109→            System.err.println(Utils.stackTrace(e));
   110→            Exit.exit(1);
   111→        }
   112→    }
   113→
   114→    protected static void printHeader(boolean showDetailedStats) {
   115→        String newFieldsInHeader = ", rebalance.time.ms, fetch.time.ms, fetch.MB.sec, fetch.nMsg.sec";
   116→        if (!showDetailedStats)
   117→            System.out.printf("start.time, end.time, data.consumed.in.MB, MB.sec, data.consumed.in.nMsg, nMsg.sec%s%n", newFieldsInHeader);
   118→        else
   119→            System.out.printf("time, threadId, data.consumed.in.MB, MB.sec, data.consumed.in.nMsg, nMsg.sec%s%n", newFieldsInHeader);
   120→    }
   121→
   122→    private static void consume(KafkaConsumer<byte[], byte[]> consumer,
   123→                                ConsumerPerfOptions options,
   124→                                AtomicLong totalMessagesRead,
   125→                                AtomicLong totalBytesRead,
   126→                                AtomicLong joinTimeMs,
   127→                                long bytesRead,
   128→                                long messagesRead,
   129→                                long lastBytesRead,
   130→                                long lastMessagesRead,
   131→                                long joinStartMs,
   132→                                AtomicLong joinTimeMsInSingleRound) {
   133→        long numMessages = options.numMessages();
   134→        long recordFetchTimeoutMs = options.recordFetchTimeoutMs();
   135→        long reportingIntervalMs = options.reportingIntervalMs();
   136→        boolean showDetailedStats = options.showDetailedStats();
   137→        SimpleDateFormat dateFormat = options.dateFormat();
   138→        consumer.subscribe(options.topic(),
   139→            new ConsumerPerfRebListener(joinTimeMs, joinStartMs, joinTimeMsInSingleRound));
   140→
   141→        // now start the benchmark
   142→        long currentTimeMs = System.currentTimeMillis();
   143→        long lastReportTimeMs = currentTimeMs;
   144→        long lastConsumedTimeMs = currentTimeMs;
   145→
   146→        while (messagesRead < numMessages && currentTimeMs - lastConsumedTimeMs <= recordFetchTimeoutMs) {
   147→            ConsumerRecords<byte[], byte[]> records = consumer.poll(Duration.ofMillis(100));
   148→            currentTimeMs = System.currentTimeMillis();
   149→            if (!records.isEmpty())
   150→                lastConsumedTimeMs = currentTimeMs;
   151→            for (ConsumerRecord<byte[], byte[]> record : records) {
   152→                messagesRead += 1;
   153→                if (record.key() != null)
   154→                    bytesRead += record.key().length;
   155→                if (record.value() != null)
   156→                    bytesRead += record.value().length;
   157→                if (currentTimeMs - lastReportTimeMs >= reportingIntervalMs) {
   158→                    if (showDetailedStats)
   159→                        printConsumerProgress(0, bytesRead, lastBytesRead, messagesRead, lastMessagesRead,
   160→                            lastReportTimeMs, currentTimeMs, dateFormat, joinTimeMsInSingleRound.get());
   161→                    joinTimeMsInSingleRound = new AtomicLong(0);
   162→                    lastReportTimeMs = currentTimeMs;
   163→                    lastMessagesRead = messagesRead;
   164→                    lastBytesRead = bytesRead;
   165→                }
   166→            }
   167→        }
   168→
   169→        if (messagesRead < numMessages)
   170→            System.out.printf("WARNING: Exiting before consuming the expected number of messages: timeout (%d ms) exceeded. " +
   171→                "You can use the --timeout option to increase the timeout.%n", recordFetchTimeoutMs);
   172→        totalMessagesRead.set(messagesRead);
   173→        totalBytesRead.set(bytesRead);
   174→    }
   175→
   176→    protected static void printConsumerProgress(int id,
   177→                                                long bytesRead,
   178→                                                long lastBytesRead,
   179→                                                long messagesRead,
   180→                                                long lastMessagesRead,
   181→                                                long startMs,
   182→                                                long endMs,
   183→                                                SimpleDateFormat dateFormat,
   184→                                                long joinTimeMsInSingleRound) {
   185→        printBasicProgress(id, bytesRead, lastBytesRead, messagesRead, lastMessagesRead, startMs, endMs, dateFormat);
   186→        printExtendedProgress(bytesRead, lastBytesRead, messagesRead, lastMessagesRead, startMs, endMs, joinTimeMsInSingleRound);
   187→        System.out.println();
   188→    }
   189→
   190→    private static void printBasicProgress(int id,
   191→                                           long bytesRead,
   192→                                           long lastBytesRead,
   193→                                           long messagesRead,
   194→                                           long lastMessagesRead,
   195→                                           long startMs,
   196→                                           long endMs,
   197→                                           SimpleDateFormat dateFormat) {
   198→        double elapsedMs = endMs - startMs;
   199→        double totalMbRead = (bytesRead * 1.0) / (1024 * 1024);
   200→        double intervalMbRead = ((bytesRead - lastBytesRead) * 1.0) / (1024 * 1024);
   201→        double intervalMbPerSec = 1000.0 * intervalMbRead / elapsedMs;
   202→        double intervalMessagesPerSec = ((messagesRead - lastMessagesRead) / elapsedMs) * 1000.0;
   203→        System.out.printf("%s, %d, %.4f, %.4f, %d, %.4f", dateFormat.format(endMs), id,
   204→            totalMbRead, intervalMbPerSec, messagesRead, intervalMessagesPerSec);
   205→    }
   206→
   207→    private static void printExtendedProgress(long bytesRead,
   208→                                              long lastBytesRead,
   209→                                              long messagesRead,
   210→                                              long lastMessagesRead,
   211→                                              long startMs,
   212→                                              long endMs,
   213→                                              long joinTimeMsInSingleRound) {
   214→        long fetchTimeMs = endMs - startMs - joinTimeMsInSingleRound;
   215→        double intervalMbRead = ((bytesRead - lastBytesRead) * 1.0) / (1024 * 1024);
   216→        long intervalMessagesRead = messagesRead - lastMessagesRead;
   217→        double intervalMbPerSec = (fetchTimeMs <= 0) ? 0.0 : 1000.0 * intervalMbRead / fetchTimeMs;
   218→        double intervalMessagesPerSec = (fetchTimeMs <= 0) ? 0.0 : 1000.0 * intervalMessagesRead / fetchTimeMs;
   219→        System.out.printf(", %d, %d, %.4f, %.4f", joinTimeMsInSingleRound,
   220→            fetchTimeMs, intervalMbPerSec, intervalMessagesPerSec);
   221→    }
   222→
   223→    public static class ConsumerPerfRebListener implements ConsumerRebalanceListener {
   224→        private AtomicLong joinTimeMs;
   225→        private AtomicLong joinTimeMsInSingleRound;
   226→        private long joinStartMs;
   227→
   228→        public ConsumerPerfRebListener(AtomicLong joinTimeMs, long joinStartMs, AtomicLong joinTimeMsInSingleRound) {
   229→            this.joinTimeMs = joinTimeMs;
   230→            this.joinStartMs = joinStartMs;
   231→            this.joinTimeMsInSingleRound = joinTimeMsInSingleRound;
   232→        }
   233→
   234→        @Override
   235→        public void onPartitionsRevoked(Collection<TopicPartition> partitions) {
   236→            joinStartMs = System.currentTimeMillis();
   237→        }
   238→
   239→        @Override
   240→        public void onPartitionsAssigned(Collection<TopicPartition> partitions) {
   241→            long elapsedMs = System.currentTimeMillis() - joinStartMs;
   242→            joinTimeMs.addAndGet(elapsedMs);
   243→            joinTimeMsInSingleRound.addAndGet(elapsedMs);
   244→        }
   245→    }
   246→
   247→    protected static class ConsumerPerfOptions extends CommandDefaultOptions {
   248→        private final OptionSpec<String> bootstrapServerOpt;
   249→        private final OptionSpec<String> topicOpt;
   250→        private final OptionSpec<String> groupIdOpt;
   251→        private final OptionSpec<Integer> fetchSizeOpt;
   252→        private final OptionSpec<Void> resetBeginningOffsetOpt;
   253→        private final OptionSpec<Integer> socketBufferSizeOpt;
   254→        private final OptionSpec<String> consumerConfigOpt;
   255→        private final OptionSpec<Void> printMetricsOpt;
   256→        private final OptionSpec<Void> showDetailedStatsOpt;
   257→        private final OptionSpec<Long> recordFetchTimeoutOpt;
   258→        private final OptionSpec<Long> numMessagesOpt;
   259→        private final OptionSpec<Long> reportingIntervalOpt;
   260→        private final OptionSpec<String> dateFormatOpt;
   261→        private final OptionSpec<Void> hideHeaderOpt;
   262→
   263→        public ConsumerPerfOptions(String[] args) {
   264→            super(args);
   265→            bootstrapServerOpt = parser.accepts("bootstrap-server", "REQUIRED: The server(s) to connect to.")
   266→                .withRequiredArg()
   267→                .describedAs("server to connect to")
   268→                .ofType(String.class);
   269→            topicOpt = parser.accepts("topic", "REQUIRED: The topic to consume from.")
   270→                .withRequiredArg()
   271→                .describedAs("topic")
   272→                .ofType(String.class);
   273→            groupIdOpt = parser.accepts("group", "The group id to consume on.")
   274→                .withRequiredArg()
   275→                .describedAs("gid")
   276→                .defaultsTo("perf-consumer-" + RND.nextInt(100_000))
   277→                .ofType(String.class);
   278→            fetchSizeOpt = parser.accepts("fetch-size", "The amount of data to fetch in a single request.")
   279→                .withRequiredArg()
   280→                .describedAs("size")
   281→                .ofType(Integer.class)
   282→                .defaultsTo(1024 * 1024);
   283→            resetBeginningOffsetOpt = parser.accepts("from-latest", "If the consumer does not already have an established " +
   284→                "offset to consume from, start with the latest message present in the log rather than the earliest message.");
   285→            socketBufferSizeOpt = parser.accepts("socket-buffer-size", "The size of the tcp RECV size.")
   286→                .withRequiredArg()
   287→                .describedAs("size")
   288→                .ofType(Integer.class)
   289→                .defaultsTo(2 * 1024 * 1024);
   290→            consumerConfigOpt = parser.accepts("consumer.config", "Consumer config properties file.")
   291→                .withRequiredArg()
   292→                .describedAs("config file")
   293→                .ofType(String.class);
   294→            printMetricsOpt = parser.accepts("print-metrics", "Print out the metrics.");
   295→            showDetailedStatsOpt = parser.accepts("show-detailed-stats", "If set, stats are reported for each reporting " +
   296→                "interval as configured by reporting-interval");
   297→            recordFetchTimeoutOpt = parser.accepts("timeout", "The maximum allowed time in milliseconds between returned records.")
   298→                .withOptionalArg()
   299→                .describedAs("milliseconds")
   300→                .ofType(Long.class)
   301→                .defaultsTo(10_000L);
   302→            numMessagesOpt = parser.accepts("messages", "REQUIRED: The number of messages to send or consume")
   303→                .withRequiredArg()
   304→                .describedAs("count")
   305→                .ofType(Long.class);
   306→            reportingIntervalOpt = parser.accepts("reporting-interval", "Interval in milliseconds at which to print progress info.")
   307→                .withRequiredArg()
   308→                .withValuesConvertedBy(regex("^\\d+$"))
   309→                .describedAs("interval_ms")
   310→                .ofType(Long.class)
   311→                .defaultsTo(5_000L);
   312→            dateFormatOpt = parser.accepts("date-format", "The date format to use for formatting the time field. " +
   313→                    "See java.text.SimpleDateFormat for options.")
   314→                .withRequiredArg()
   315→                .describedAs("date format")
   316→                .ofType(String.class)
   317→                .defaultsTo("yyyy-MM-dd HH:mm:ss:SSS");
   318→            hideHeaderOpt = parser.accepts("hide-header", "If set, skips printing the header for the stats");
   319→            try {
   320→                options = parser.parse(args);
   321→            } catch (OptionException e) {
   322→                CommandLineUtils.printUsageAndExit(parser, e.getMessage());
   323→                return;
   324→            }
   325→            if (options != null) {
   326→                CommandLineUtils.maybePrintHelpOrVersion(this, "This tool is used to verify the consumer performance.");
   327→                CommandLineUtils.checkRequiredArgs(parser, options, topicOpt, numMessagesOpt);
   328→            }
   329→        }
   330→
   331→        public boolean printMetrics() {
   332→            return options.has(printMetricsOpt);
   333→        }
   334→
   335→        public String brokerHostsAndPorts() {
   336→            return options.valueOf(bootstrapServerOpt);
   337→        }
   338→
   339→        public Properties props() throws IOException {
   340→            Properties props = (options.has(consumerConfigOpt))
   341→                ? Utils.loadProps(options.valueOf(consumerConfigOpt))
   342→                : new Properties();
   343→            props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, brokerHostsAndPorts());
   344→            props.put(ConsumerConfig.GROUP_ID_CONFIG, options.valueOf(groupIdOpt));
   345→            props.put(ConsumerConfig.RECEIVE_BUFFER_CONFIG, options.valueOf(socketBufferSizeOpt).toString());
   346→            props.put(ConsumerConfig.MAX_PARTITION_FETCH_BYTES_CONFIG, options.valueOf(fetchSizeOpt).toString());
   347→            props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG,
   348→                options.has(resetBeginningOffsetOpt) ? "latest" : "earliest");
   349→            props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, ByteArrayDeserializer.class);
   350→            props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, ByteArrayDeserializer.class);
   351→            props.put(ConsumerConfig.CHECK_CRCS_CONFIG, "false");
   352→            if (props.getProperty(ConsumerConfig.CLIENT_ID_CONFIG) == null)
   353→                props.put(ConsumerConfig.CLIENT_ID_CONFIG, "perf-consumer-client");
   354→            return props;
   355→        }
   356→
   357→        public Set<String> topic() {
   358→            return Collections.singleton(options.valueOf(topicOpt));
   359→        }
   360→
   361→        public long numMessages() {
   362→            return options.valueOf(numMessagesOpt);
   363→        }
   364→
   365→        public long reportingIntervalMs() {
   366→            long value = options.valueOf(reportingIntervalOpt);
   367→            if (value <= 0)
   368→                throw new IllegalArgumentException("Reporting interval must be greater than 0.");
   369→            return value;
   370→        }
   371→
   372→        public boolean showDetailedStats() {
   373→            return options.has(showDetailedStatsOpt);
   374→        }
   375→
   376→        public SimpleDateFormat dateFormat() {
   377→            return new SimpleDateFormat(options.valueOf(dateFormatOpt));
   378→        }
   379→
   380→        public boolean hideHeader() {
   381→            return options.has(hideHeaderOpt);
   382→        }
   383→
   384→        public long recordFetchTimeoutMs() {
   385→            return options.valueOf(recordFetchTimeoutOpt);
   386→        }
   387→    }
   388→}
