    92→public class VerifiableConsumer implements Closeable, OffsetCommitCallback, ConsumerRebalanceListener {
    93→
    94→    private static final Logger log = LoggerFactory.getLogger(VerifiableConsumer.class);
    95→
    96→    private final ObjectMapper mapper = new ObjectMapper();
    97→    private final PrintStream out;
    98→    private final KafkaConsumer<String, String> consumer;
    99→    private final String topic;
   100→    private final boolean useAutoCommit;
   101→    private final boolean useAsyncCommit;
   102→    private final boolean verbose;
   103→    private final int maxMessages;
   104→    private final CountDownLatch shutdownLatch = new CountDownLatch(1);
   105→    private int consumedMessages = 0;
   106→
   107→    public VerifiableConsumer(KafkaConsumer<String, String> consumer,
   108→                              PrintStream out,
   109→                              String topic,
   110→                              int maxMessages,
   111→                              boolean useAutoCommit,
   112→                              boolean useAsyncCommit,
   113→                              boolean verbose) {
   114→        this.consumer = consumer;
   115→        this.out = out;
   116→        this.topic = topic;
   117→        this.maxMessages = maxMessages;
   118→        this.useAutoCommit = useAutoCommit;
   119→        this.useAsyncCommit = useAsyncCommit;
   120→        this.verbose = verbose;
   121→        addKafkaSerializerModule();
   122→    }
   123→
   124→    private void addKafkaSerializerModule() {
   125→        SimpleModule kafka = new SimpleModule();
   126→        kafka.addSerializer(TopicPartition.class, new JsonSerializer<TopicPartition>() {
   127→            @Override
   128→            public void serialize(TopicPartition tp, JsonGenerator gen, SerializerProvider serializers) throws IOException {
   129→                gen.writeStartObject();
   130→                gen.writeObjectField("topic", tp.topic());
   131→                gen.writeObjectField("partition", tp.partition());
   132→                gen.writeEndObject();
   133→            }
   134→        });
   135→        mapper.registerModule(kafka);
   136→    }
   137→
   138→    private boolean hasMessageLimit() {
   139→        return maxMessages >= 0;
   140→    }
   141→
   142→    private boolean isFinished() {
   143→        return hasMessageLimit() && consumedMessages >= maxMessages;
   144→    }
   145→
   146→    private Map<TopicPartition, OffsetAndMetadata> onRecordsReceived(ConsumerRecords<String, String> records) {
   147→        Map<TopicPartition, OffsetAndMetadata> offsets = new HashMap<>();
   148→
   149→        List<RecordSetSummary> summaries = new ArrayList<>();
   150→        for (TopicPartition tp : records.partitions()) {
   151→            List<ConsumerRecord<String, String>> partitionRecords = records.records(tp);
   152→
   153→            if (hasMessageLimit() && consumedMessages + partitionRecords.size() > maxMessages)
   154→                partitionRecords = partitionRecords.subList(0, maxMessages - consumedMessages);
   155→
   156→            if (partitionRecords.isEmpty())
   157→                continue;
   158→
   159→            long minOffset = partitionRecords.get(0).offset();
   160→            long maxOffset = partitionRecords.get(partitionRecords.size() - 1).offset();
   161→
   162→            offsets.put(tp, new OffsetAndMetadata(maxOffset + 1));
   163→            summaries.add(new RecordSetSummary(tp.topic(), tp.partition(),
   164→                    partitionRecords.size(), minOffset, maxOffset));
   165→
   166→            if (verbose) {
   167→                for (ConsumerRecord<String, String> record : partitionRecords) {
   168→                    printJson(new RecordData(record));
   169→                }
   170→            }
   171→
   172→            consumedMessages += partitionRecords.size();
   173→            if (isFinished())
   174→                break;
   175→        }
   176→
   177→        printJson(new RecordsConsumed(records.count(), summaries));
   178→        return offsets;
   179→    }
