   483→        public RecordSetSummary(String topic, int partition, long count, long minOffset, long maxOffset) {
   484→            super(topic, partition);
   485→            this.count = count;
   486→            this.minOffset = minOffset;
   487→            this.maxOffset = maxOffset;
   488→        }
   489→
   490→        @JsonProperty
   491→        public long count() {
   492→            return count;
   493→        }
   494→
   495→        @JsonProperty
   496→        public long minOffset() {
   497→            return minOffset;
   498→        }
   499→
   500→        @JsonProperty
   501→        public long maxOffset() {
   502→            return maxOffset;
   503→        }
   504→
   505→    }
   506→
   507→    private static ArgumentParser argParser() {
   508→        ArgumentParser parser = ArgumentParsers
   509→                .newArgumentParser("verifiable-consumer")
   510→                .defaultHelp(true)
   511→                .description("This tool consumes messages from a specific topic and emits consumer events (e.g. group rebalances, received messages, and offsets committed) as JSON objects to STDOUT.");
   512→        MutuallyExclusiveGroup connectionGroup = parser.addMutuallyExclusiveGroup("Connection Group")
   513→                .description("Group of arguments for connection to brokers")
   514→                .required(true);
   515→        connectionGroup.addArgument("--bootstrap-server")
   516→                .action(store())
   517→                .required(true)
   518→                .type(String.class)
   519→                .metavar("HOST1:PORT1[,HOST2:PORT2[...]]")
   520→                .dest("bootstrapServer")
   521→                .help("The server(s) to connect to. Comma-separated list of Kafka brokers in the form HOST1:PORT1,HOST2:PORT2,...");
   522→
   523→        parser.addArgument("--topic")
   524→                .action(store())
   525→                .required(true)
   526→                .type(String.class)
   527→                .metavar("TOPIC")
   528→                .help("Consumes messages from this topic.");
   529→
   530→        parser.addArgument("--group-protocol")
   531→                .action(store())
   532→                .required(false)
   533→                .type(String.class)
   534→                .setDefault(ConsumerConfig.DEFAULT_GROUP_PROTOCOL)
   535→                .metavar("GROUP_PROTOCOL")
   536→                .dest("groupProtocol")
   537→                .help(String.format("Group protocol (must be one of %s)", Arrays.stream(GroupProtocol.values())
   538→                        .map(Object::toString).collect(Collectors.joining(", "))));
   539→
   540→        parser.addArgument("--group-remote-assignor")
   541→                .action(store())
   542→                .required(false)
   543→                .type(String.class)
   544→                .setDefault(ConsumerConfig.DEFAULT_GROUP_REMOTE_ASSIGNOR)
   545→                .metavar("GROUP_REMOTE_ASSIGNOR")
   546→                .dest("groupRemoteAssignor")
   547→                .help(String.format("Group remote assignor; only used if the group protocol is %s", GroupProtocol.CONSUMER.name()));
   548→
   549→        parser.addArgument("--group-id")
   550→                .action(store())
   551→                .required(true)
   552→                .type(String.class)
   553→                .metavar("GROUP_ID")
   554→                .dest("groupId")
   555→                .help("The groupId shared among members of the consumer group");
   556→
   557→        parser.addArgument("--group-instance-id")
   558→                .action(store())
   559→                .required(false)
   560→                .type(String.class)
   561→                .metavar("GROUP_INSTANCE_ID")
   562→                .dest("groupInstanceId")
   563→                .help("A unique identifier of the consumer instance");
   564→
   565→        parser.addArgument("--max-messages")
   566→                .action(store())
   567→                .required(false)
   568→                .type(Integer.class)
   569→                .setDefault(-1)
   570→                .metavar("MAX-MESSAGES")
   571→                .dest("maxMessages")
   572→                .help("Consume this many messages. If -1 (the default), the consumer will consume until the process is killed externally");
   573→
   574→        parser.addArgument("--session-timeout")
   575→                .action(store())
   576→                .required(false)
   577→                .type(Integer.class)
   578→                .metavar("TIMEOUT_MS")
   579→                .dest("sessionTimeout")
   580→                .help("Set the consumer's session timeout, note that this configuration is not supported when group protocol is consumer");
   581→
   582→        parser.addArgument("--verbose")
   583→                .action(storeTrue())
   584→                .type(Boolean.class)
   585→                .metavar("VERBOSE")
   586→                .help("Enable to log individual consumed records");
   587→
   588→        parser.addArgument("--enable-autocommit")
   589→                .action(storeTrue())
   590→                .type(Boolean.class)
   591→                .metavar("ENABLE-AUTOCOMMIT")
   592→                .dest("useAutoCommit")
   593→                .help("Enable offset auto-commit on consumer");
   594→
   595→        parser.addArgument("--reset-policy")
   596→                .action(store())
   597→                .required(false)
   598→                .setDefault("earliest")
   599→                .type(String.class)
   600→                .dest("resetPolicy")
   601→                .help("Set reset policy (must be either 'earliest', 'latest', or 'none'");
   602→
   603→        parser.addArgument("--assignment-strategy")
   604→                .action(store())
   605→                .required(false)
   606→                .setDefault(RangeAssignor.class.getName())
   607→                .type(String.class)
   608→                .dest("assignmentStrategy")
   609→                .help(String.format("Set assignment strategy (e.g. %s); only used if the group protocol is %s", RoundRobinAssignor.class.getName(), GroupProtocol.CLASSIC.name()));
   610→
   611→        parser.addArgument("--consumer.config")
   612→                .action(store())
   613→                .required(false)
   614→                .type(String.class)
   615→                .metavar("CONFIG_FILE")
   616→                .help("Consumer config properties file (config options shared with command line parameters will be overridden).");
   617→
   618→        return parser;
   619→    }
   620→
   621→    public static VerifiableConsumer createFromArgs(ArgumentParser parser, String[] args) throws ArgumentParserException {
   622→        Namespace res = parser.parseArgs(args);
   623→
   624→        boolean useAutoCommit = res.getBoolean("useAutoCommit");
   625→        String configFile = res.getString("consumer.config");
   626→        String brokerHostandPort = res.getString("bootstrapServer");
   627→
   628→        Properties consumerProps = new Properties();
   629→        if (configFile != null) {
   630→            try {
   631→                consumerProps.putAll(Utils.loadProps(configFile));
   632→            } catch (IOException e) {
   633→                throw new ArgumentParserException(e.getMessage(), parser);
   634→            }
   635→        }
   636→
   637→        GroupProtocol groupProtocol = GroupProtocol.of(res.getString("groupProtocol"));
   638→        consumerProps.put(ConsumerConfig.GROUP_PROTOCOL_CONFIG, groupProtocol.name());
   639→
   640→        // 3.7.0 includes support for KIP-848 which introduced a new implementation of the consumer group protocol.
   641→        // The two implementations use slightly different configuration, hence these arguments are conditional.
   642→        //
   643→        // See the Python class/method VerifiableConsumer.start_cmd() in verifiable_consumer.py for how the
   644→        // command line arguments are passed in by the system test framework.
   645→        if (groupProtocol == GroupProtocol.CONSUMER) {
   646→            String groupRemoteAssignor = res.getString("groupRemoteAssignor");
   647→
   648→            if (groupRemoteAssignor != null)
   649→                consumerProps.put(ConsumerConfig.GROUP_REMOTE_ASSIGNOR_CONFIG, groupRemoteAssignor);
   650→        } else {
   651→            // This means we're using the CLASSIC consumer group protocol.
   652→            consumerProps.put(ConsumerConfig.PARTITION_ASSIGNMENT_STRATEGY_CONFIG, res.getString("assignmentStrategy"));
   653→        }
   654→
   655→        Integer sessionTimeout = res.getInt("sessionTimeout");
   656→        if (sessionTimeout != null) {
   657→            consumerProps.put(ConsumerConfig.SESSION_TIMEOUT_MS_CONFIG, Integer.toString(sessionTimeout));
   658→        }
   659→
   660→        consumerProps.put(ConsumerConfig.GROUP_ID_CONFIG, res.getString("groupId"));
   661→
   662→        String groupInstanceId = res.getString("groupInstanceId");
   663→        if (groupInstanceId != null) {
   664→            consumerProps.put(ConsumerConfig.GROUP_INSTANCE_ID_CONFIG, groupInstanceId);
   665→        }
   666→
   667→        consumerProps.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, brokerHostandPort);
   668→
   669→        consumerProps.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, useAutoCommit);
   670→        consumerProps.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, res.getString("resetPolicy"));
   671→
   672→        StringDeserializer deserializer = new StringDeserializer();
   673→        KafkaConsumer<String, String> consumer = new KafkaConsumer<>(consumerProps, deserializer, deserializer);
   674→
   675→        String topic = res.getString("topic");
   676→        int maxMessages = res.getInt("maxMessages");
   677→        boolean verbose = res.getBoolean("verbose");
   678→
   679→        return new VerifiableConsumer(
   680→                consumer,
   681→                System.out,
   682→                topic,
   683→                maxMessages,
   684→                useAutoCommit,
   685→                false,
   686→                verbose);
   687→    }
   688→
   689→    public static void main(String[] args) {
   690→        ArgumentParser parser = argParser();
   691→        if (args.length == 0) {
   692→            parser.printHelp();
   693→            // Can't use `Exit.exit` here because it didn't exist until 0.11.0.0.
   694→            System.exit(0);
   695→        }
   696→        try {
   697→            final VerifiableConsumer consumer = createFromArgs(parser, args);
   698→            // Can't use `Exit.addShutdownHook` here because it didn't exist until 2.5.0.
   699→            Runtime.getRuntime().addShutdownHook(new Thread(consumer::close, "verifiable-consumer-shutdown-hook"));
   700→
   701→            consumer.run();
   702→        } catch (ArgumentParserException e) {
   703→            parser.handleError(e);
   704→            // Can't use `Exit.exit` here because it didn't exist until 0.11.0.0.
   705→            System.exit(1);
   706→        }
   707→    }
   708→
   709→}
