   621→    public static VerifiableConsumer createFromArgs(ArgumentParser parser, String[] args) throws ArgumentParserException {
   622→        Namespace res = parser.parseArgs(args);
   623→
   624→        boolean useAutoCommit = res.getBoolean("useAutoCommit");
   625→        String configFile = res.getString("consumer.config");
   626→        String brokerHostandPort = res.getString("bootstrapServer");
   627→
   628→        Properties consumerProps = new Properties();
   629→        if (configFile != null) {
   630→            try {
   631→                consumerProps.putAll(Utils.loadProps(configFile));
   632→            } catch (IOException e) {
   633→                throw new ArgumentParserException(e.getMessage(), parser);
   634→            }
   635→        }
   636→
   637→        GroupProtocol groupProtocol = GroupProtocol.of(res.getString("groupProtocol"));
   638→        consumerProps.put(ConsumerConfig.GROUP_PROTOCOL_CONFIG, groupProtocol.name());
   639→
   640→        // 3.7.0 includes support for KIP-848 which introduced a new implementation of the consumer group protocol.
   641→        // The two implementations use slightly different configuration, hence these arguments are conditional.
   642→        //
   643→        // See the Python class/method VerifiableConsumer.start_cmd() in verifiable_consumer.py for how the
   644→        // command line arguments are passed in by the system test framework.
   645→        if (groupProtocol == GroupProtocol.CONSUMER) {
   646→            String groupRemoteAssignor = res.getString("groupRemoteAssignor");
   647→
   648→            if (groupRemoteAssignor != null)
   649→                consumerProps.put(ConsumerConfig.GROUP_REMOTE_ASSIGNOR_CONFIG, groupRemoteAssignor);
   650→        } else {
   651→            // This means we're using the CLASSIC consumer group protocol.
   652→            consumerProps.put(ConsumerConfig.PARTITION_ASSIGNMENT_STRATEGY_CONFIG, res.getString("assignmentStrategy"));
   653→        }
   654→
   655→        Integer sessionTimeout = res.getInt("sessionTimeout");
   656→        if (sessionTimeout != null) {
   657→            consumerProps.put(ConsumerConfig.SESSION_TIMEOUT_MS_CONFIG, Integer.toString(sessionTimeout));
   658→        }
   659→
   660→        consumerProps.put(ConsumerConfig.GROUP_ID_CONFIG, res.getString("groupId"));
   661→
   662→        String groupInstanceId = res.getString("groupInstanceId");
   663→        if (groupInstanceId != null) {
   664→            consumerProps.put(ConsumerConfig.GROUP_INSTANCE_ID_CONFIG, groupInstanceId);
   665→        }
   666→
   667→        consumerProps.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, brokerHostandPort);
   668→
   669→        consumerProps.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, useAutoCommit);
   670→        consumerProps.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, res.getString("resetPolicy"));
   671→
   672→        StringDeserializer deserializer = new StringDeserializer();
   673→        KafkaConsumer<String, String> consumer = new KafkaConsumer<>(consumerProps, deserializer, deserializer);
