    45→
    46→/**
    47→ * Consumer that dumps messages to standard out.
    48→ */
    49→public class ConsoleConsumer {
    50→
    51→    private static final Logger LOG = LoggerFactory.getLogger(ConsoleConsumer.class);
    52→    private static final CountDownLatch SHUTDOWN_LATCH = new CountDownLatch(1);
    53→
    54→    static int messageCount = 0;
    55→
    56→    public static void main(String[] args) throws Exception {
    57→        ConsoleConsumerOptions opts = new ConsoleConsumerOptions(args);
    58→        try {
    59→            run(opts);
    60→        } catch (AuthenticationException ae) {
    61→            LOG.error("Authentication failed: terminating consumer process", ae);
    62→            Exit.exit(1);
    63→        } catch (Throwable t) {
    64→            LOG.error("Unknown error when running consumer: ", t);
    65→            Exit.exit(1);
    66→        }
    67→    }
    68→
    69→    public static void run(ConsoleConsumerOptions opts) {
    70→        messageCount = 0;
    71→        Consumer<byte[], byte[]> consumer = new KafkaConsumer<>(opts.consumerProps(), new ByteArrayDeserializer(), new ByteArrayDeserializer());
    72→        ConsumerWrapper consumerWrapper = new ConsumerWrapper(opts, consumer);
    73→
    74→        addShutdownHook(consumerWrapper, opts);
    75→
    76→        try {
    77→            process(opts.maxMessages(), opts.formatter(), consumerWrapper, System.out, opts.skipMessageOnError());
    78→        } finally {
    79→            consumerWrapper.cleanup();
    80→            opts.formatter().close();
    81→            reportRecordCount();
    82→
    83→            SHUTDOWN_LATCH.countDown();
    84→        }
    85→    }
    86→
    87→    static void addShutdownHook(ConsumerWrapper consumer, ConsoleConsumerOptions conf) {
    88→        Exit.addShutdownHook("consumer-shutdown-hook", () -> {
    89→            try {
    90→                consumer.wakeup();
    91→                SHUTDOWN_LATCH.await();
    92→            } catch (Throwable t) {
    93→                LOG.error("Exception while running shutdown hook: ", t);
    94→            }
    95→            if (conf.enableSystestEventsLogging()) {
    96→                System.out.println("shutdown_complete");
    97→            }
    98→        });
    99→    }
   100→
   101→    static void process(int maxMessages, MessageFormatter formatter, ConsumerWrapper consumer, PrintStream output, boolean skipMessageOnError) {
   102→        while (messageCount < maxMessages || maxMessages == -1) {
   103→            ConsumerRecord<byte[], byte[]> msg;
   104→            try {
   105→                msg = consumer.receive();
   106→            } catch (WakeupException we) {
   107→                LOG.trace("Caught WakeupException because consumer is shutdown, ignore and terminate.");
