   109→                return;
   110→            } catch (Throwable t) {
   111→                LOG.error("Error processing message, terminating consumer process: ", t);
   112→                // Consumer will be closed
   113→                return;
   114→            }
   115→            messageCount += 1;
   116→            try {
   117→                formatter.writeTo(new ConsumerRecord<>(msg.topic(), msg.partition(), msg.offset(), msg.timestamp(), msg.timestampType(),
   118→                    0, 0, msg.key(), msg.value(), msg.headers(), Optional.empty()), output);
   119→            } catch (Throwable t) {
   120→                if (skipMessageOnError) {
   121→                    LOG.error("Error processing message, skipping this message: ", t);
   122→                } else {
   123→                    // Consumer will be closed
   124→                    throw t;
   125→                }
   126→            }
   127→            if (checkErr(output)) {
   128→                // Consumer will be closed
   129→                return;
   130→            }
   131→        }
   132→    }
   133→
   134→    static void reportRecordCount() {
   135→        System.err.println("Processed a total of " + messageCount + " messages");
   136→    }
   137→
   138→    static boolean checkErr(PrintStream output) {
   139→        boolean gotError = output.checkError();
   140→        if (gotError) {
   141→            // This means no one is listening to our output stream anymore, time to shut down
   142→            System.err.println("Unable to write to standard out, closing consumer.");
   143→        }
   144→        return gotError;
   145→    }
   146→
   147→    public static class ConsumerWrapper {
   148→        final Time time = Time.SYSTEM;
   149→        final long timeoutMs;
   150→        final Consumer<byte[], byte[]> consumer;
   151→
   152→        Iterator<ConsumerRecord<byte[], byte[]>> recordIter = Collections.emptyIterator();
   153→
   154→        public ConsumerWrapper(ConsoleConsumerOptions opts, Consumer<byte[], byte[]> consumer) {
   155→            this.consumer = consumer;
   156→            timeoutMs = opts.timeoutMs();
   157→            Optional<String> topic = opts.topicArg();
   158→
   159→            if (topic.isPresent()) {
   160→                if (opts.partitionArg().isPresent()) {
