   162→                } else {
   163→                    consumer.subscribe(Collections.singletonList(topic.get()));
   164→                }
   165→            } else {
   166→                opts.includedTopicsArg().ifPresent(topics -> consumer.subscribe(Pattern.compile(topics)));
   167→            }
   168→        }
   169→
   170→        private void seek(String topic, int partitionId, long offset) {
   171→            TopicPartition topicPartition = new TopicPartition(topic, partitionId);
   172→            consumer.assign(Collections.singletonList(topicPartition));
   173→            if (offset == ListOffsetsRequest.EARLIEST_TIMESTAMP) {
   174→                consumer.seekToBeginning(Collections.singletonList(topicPartition));
   175→            } else if (offset == ListOffsetsRequest.LATEST_TIMESTAMP) {
   176→                consumer.seekToEnd(Collections.singletonList(topicPartition));
   177→            } else {
   178→                consumer.seek(topicPartition, offset);
   179→            }
   180→        }
