            LOG.info("Processing message - Topic: {}, Partition: {}, Offset: {}, Key: {}, Value: {}",
                    record.topic(), record.partition(), record.offset(), record.key(), record.value());
            // Idempotent processing: implementation should handle duplicate messages gracefully
            // This ensures that processing the same message multiple times produces the same result
        } catch (Exception e) {
            LOG.error("Error processing record at offset {}", record.offset(), e);
        }
    }

